"use client";

import { memo, useId, useMemo, useCallback } from "react";
import type { MouseEvent } from "react";
import { defaultRelativeTime } from "./hooks/use-relative-time";
import { defaultDateFormat, toDate } from "./lib/format-default";
import { FeaturedPart } from "./parts/featured";
import { LargePart } from "./parts/large";
import { MediumPart } from "./parts/medium";
import { SmallPart } from "./parts/small";
import { ListPart } from "./parts/list";
import {
  DEFAULT_LABELS,
  type ContentCardNewsProps,
  type ResolvedPartProps,
} from "./types";

/**
 * ContentCardNews01 — magazine-style content card with 5 visual variants
 * dispatched via the `variant` prop (`featured` / `large` / `medium` / `small` / `list`).
 *
 * Renders an `<article>` with an absolute-positioned link overlay covering
 * the whole card (the "overlay-link" pattern), allowing optional `actions`
 * to live above the overlay (z-10) for nested interactives like bookmark or
 * share buttons without breaking the whole-card-clickable surface.
 *
 * All consumer-visible strings, colors, formats, and behaviors are overridable.
 */
function ContentCardNews01Impl(props: ContentCardNewsProps) {
  const {
    item,
    variant = "medium",
    href,
    onClick,
    linkComponent: LinkComponent = "a",
    formatRelativeTime,
    formatDate,
    labels: labelsProp,
    categoryStyles,
    titleClassName,
    imageClassName,
    className,
    ariaLabel: ariaLabelProp,
    actions,
    loading: loadingProp,
  } = props;

  const titleId = useId();

  const labels = useMemo(
    () => ({ ...DEFAULT_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const date = useMemo(() => toDate(item.date), [item.date]);

  const formattedRelativeTime = useMemo(() => {
    if (!date) return undefined;
    return (formatRelativeTime ?? defaultRelativeTime)(date);
  }, [date, formatRelativeTime]);

  const formattedDate = useMemo(() => {
    if (!date) return undefined;
    return (formatDate ?? defaultDateFormat)(date);
  }, [date, formatDate]);

  const categoryStyle = useMemo(() => {
    if (!item.category) return "bg-muted";
    return categoryStyles?.[item.category] ?? "bg-muted";
  }, [item.category, categoryStyles]);

  const ariaLabel =
    ariaLabelProp ?? `${labels.readArticlePrefix} ${item.title}`;

  const handleClick = useCallback(
    (event: MouseEvent) => {
      onClick?.(item, event);
    },
    [onClick, item],
  );

  const loading: "lazy" | "eager" =
    loadingProp ?? (variant === "featured" ? "eager" : "lazy");

  const partProps: ResolvedPartProps = {
    item,
    formattedDate,
    formattedRelativeTime,
    categoryStyle,
    labels,
    LinkComponent,
    href,
    onClick: onClick ? handleClick : undefined,
    ariaLabel,
    titleId,
    titleClassName,
    imageClassName,
    className,
    actions,
    loading,
  };

  switch (variant) {
    case "featured":
      return <FeaturedPart {...partProps} />;
    case "large":
      return <LargePart {...partProps} />;
    case "small":
      return <SmallPart {...partProps} />;
    case "list":
      return <ListPart {...partProps} />;
    case "medium":
    default:
      return <MediumPart {...partProps} />;
  }
}

export const ContentCardNews01 = memo(ContentCardNews01Impl);
ContentCardNews01.displayName = "ContentCardNews01";

export default ContentCardNews01;

export { ContentCardNews01, default } from "./content-card-news-01";
export type {
  ContentCardItem,
  ContentCardNewsLabels,
  ContentCardNewsProps,
  ContentCardNewsVariant,
} from "./types";
export { defaultRelativeTime } from "./hooks/use-relative-time";
export { defaultDateFormat } from "./lib/format-default";
export { meta } from "./meta";

import type { ElementType, MouseEvent, ReactNode } from "react";

export type ContentCardNewsVariant =
  | "featured"
  | "large"
  | "medium"
  | "small"
  | "list";

export interface ContentCardItem {
  /** Stable identifier. Used for React keys and the default ariaLabel. */
  id: string;
  /** Headline. Rendered in the H-tag appropriate for the variant. */
  title: string;
  /** Image URL. */
  image: string;
  /** Short summary or lead paragraph. Variants gracefully omit when absent. */
  excerpt?: string;
  /** Category / tag string. Used as a key into `categoryStyles`. */
  category?: string;
  /** Author / byline. */
  author?: string;
  /** Publish date. ISO-8601 string or Date. */
  date?: string | Date;
  /** Estimated read time in minutes. */
  readTime?: number;
  /** View count for engagement chip. Only `medium` renders this. */
  views?: number;
}

export interface ContentCardNewsLabels {
  /** Featured-variant CTA label. Default: 'Read More'. */
  readMore?: string;
  /** Compact "min" suffix for `large` variant. Default: 'min'. */
  minutesShort?: string;
  /** Long "min read" suffix for `featured` variant. Default: 'min read'. */
  minutesRead?: string;
  /** Visually-hidden label prefix on the link. Default: 'Read article:'. */
  readArticlePrefix?: string;
  /** aria-label suffix on the views chip. Default: 'views'. */
  viewsLabel?: string;
}

export const DEFAULT_LABELS: Required<ContentCardNewsLabels> = {
  readMore: "Read More",
  minutesShort: "min",
  minutesRead: "min read",
  readArticlePrefix: "Read article:",
  viewsLabel: "views",
};

export interface ContentCardNewsProps {
  /** The item to render. */
  item: ContentCardItem;

  /** Visual variant. Default: 'medium'. */
  variant?: ContentCardNewsVariant;

  /** URL the card links to. */
  href?: string;
  /** Click handler, fired before navigation if href is also set. */
  onClick?: (item: ContentCardItem, event: MouseEvent) => void;
  /** Element used for the link. Default: 'a'. Pass NextLink / RemixLink / etc. */
  linkComponent?: ElementType;

  /** Custom relative-time formatter. Default: English. */
  formatRelativeTime?: (date: Date, now?: Date) => string;
  /** Custom absolute-date formatter. Default: browser locale long format. */
  formatDate?: (date: Date) => string;
  /** Localized labels. Defaults are English. */
  labels?: ContentCardNewsLabels;

  /** Map of category → Tailwind class string. Falls back to `bg-muted` when absent. */
  categoryStyles?: Record<string, string>;
  /** Override classes for the title. */
  titleClassName?: string;
  /** Override classes for the image. */
  imageClassName?: string;
  /** Override classes for the root <article>. */
  className?: string;

  /** Override the link's accessible name. Default: '<readArticlePrefix> <title>'. */
  ariaLabel?: string;

  /** Optional cluster of buttons/links sitting ABOVE the link overlay (z-10). */
  actions?: ReactNode;

  /** Image loading strategy. Default: 'lazy' ('eager' for `featured`). */
  loading?: "lazy" | "eager";
}

/**
 * Internal shape passed from the root to each `parts/<variant>.tsx`.
 * All defaults resolved; all formatting pre-computed.
 */
export interface ResolvedPartProps {
  item: ContentCardItem;
  formattedDate: string | undefined;
  formattedRelativeTime: string | undefined;
  categoryStyle: string;
  labels: Required<ContentCardNewsLabels>;
  LinkComponent: ElementType;
  href: string | undefined;
  onClick: ((event: MouseEvent) => void) | undefined;
  ariaLabel: string;
  titleId: string;
  titleClassName: string | undefined;
  imageClassName: string | undefined;
  className: string | undefined;
  actions: ReactNode;
  loading: "lazy" | "eager";
}

import { defaultDateFormat } from "../lib/format-default";

/**
 * Default relative-time formatter — English, with absolute-date fallback
 * for dates older than ~30 days. Pure function; consumers override via
 * `formatRelativeTime` prop.
 *
 * Examples:
 *   defaultRelativeTime(today)        → "Today"
 *   defaultRelativeTime(yesterday)    → "Yesterday"
 *   defaultRelativeTime(3 days ago)   → "3 days ago"
 *   defaultRelativeTime(2 weeks ago)  → "2 weeks ago"
 *   defaultRelativeTime(2 months ago) → "March 5, 2026"
 */
export const defaultRelativeTime = (
  date: Date,
  now: Date = new Date(),
): string => {
  const diffMs = now.getTime() - date.getTime();
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  if (diffDays === 0) return "Today";
  if (diffDays === 1) return "Yesterday";
  if (diffDays < 7) return `${diffDays} days ago`;
  if (diffDays < 30) return `${Math.floor(diffDays / 7)} weeks ago`;
  return defaultDateFormat(date);
};

/**
 * Default absolute-date formatter — browser locale, long format
 * (e.g. "May 1, 2026"). Consumers override via `formatDate` prop.
 */
export const defaultDateFormat = (date: Date): string =>
  date.toLocaleDateString(undefined, {
    day: "numeric",
    month: "long",
    year: "numeric",
  });

/**
 * Coerce a `string | Date` value to `Date`. Returns `undefined` if
 * the input is itself undefined or fails to parse.
 */
export const toDate = (value: string | Date | undefined): Date | undefined => {
  if (value === undefined) return undefined;
  if (value instanceof Date) {
    return Number.isNaN(value.getTime()) ? undefined : value;
  }
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? undefined : parsed;
};

import { ArrowRight, Calendar, Clock, User } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import type { ResolvedPartProps } from "../types";

/**
 * Featured variant — full-bleed hero card. Image fills the entire surface;
 * gradient overlay puts the title + meta + CTA in legible white type.
 *
 * Badge wears a `bg-black/40 backdrop-blur-sm` chip on this variant so the
 * category color stays single-source-of-truth in `categoryStyles` while
 * remaining readable on the dark gradient.
 */
export function FeaturedPart({
  item,
  formattedRelativeTime,
  categoryStyle,
  labels,
  LinkComponent,
  href,
  onClick,
  ariaLabel,
  titleId,
  titleClassName,
  imageClassName,
  className,
  actions,
  loading,
}: ResolvedPartProps) {
  return (
    <article
      className={cn(
        "group relative h-125 overflow-hidden rounded-2xl md:h-150",
        "has-[a:focus-visible]:ring-2 has-[a:focus-visible]:ring-ring has-[a:focus-visible]:ring-offset-2",
        className,
      )}
    >
      <img
        src={item.image}
        alt={item.title}
        loading={loading}
        decoding="async"
        className={cn(
          "absolute inset-0 h-full w-full object-cover transition-transform duration-700",
          "motion-safe:group-hover:scale-105",
          imageClassName,
        )}
      />
      <div
        aria-hidden="true"
        className="absolute inset-0 bg-linear-to-t from-black via-black/50 to-transparent"
      />

      {href ? (
        <LinkComponent
          href={href}
          aria-labelledby={titleId}
          aria-label={ariaLabel}
          onClick={onClick}
          className="absolute inset-0 z-0 rounded-2xl outline-none"
        />
      ) : null}

      <div className="absolute inset-0 flex flex-col justify-end p-8 md:p-12">
        {item.category ? (
          <span className="mb-4 inline-block w-fit rounded-full bg-black/40 backdrop-blur-sm">
            <Badge
              className={cn(categoryStyle)}
              aria-label={`Category: ${item.category}`}
            >
              {item.category}
            </Badge>
          </span>
        ) : null}

        <h2
          id={titleId}
          className={cn(
            "mb-4 font-serif text-3xl font-bold leading-tight text-white md:text-4xl lg:text-5xl",
            titleClassName,
          )}
        >
          {item.title}
        </h2>

        {item.excerpt ? (
          <p className="mb-6 max-w-3xl text-lg text-white/80 line-clamp-3 md:text-xl">
            {item.excerpt}
          </p>
        ) : null}

        <div className="flex flex-wrap items-center gap-6 text-white/70">
          {item.author ? (
            <div className="flex items-center gap-2">
              <User aria-hidden="true" className="h-4 w-4" />
              <span>{item.author}</span>
            </div>
          ) : null}
          {formattedRelativeTime ? (
            <div className="flex items-center gap-2">
              <Calendar aria-hidden="true" className="h-4 w-4" />
              <span>{formattedRelativeTime}</span>
            </div>
          ) : null}
          {item.readTime !== undefined ? (
            <div className="flex items-center gap-2">
              <Clock aria-hidden="true" className="h-4 w-4" />
              <span>
                {item.readTime} {labels.minutesRead}
              </span>
            </div>
          ) : null}
          {href ? (
            <span className="ml-auto inline-flex items-center gap-2 text-white transition-colors motion-safe:group-hover:text-primary">
              {labels.readMore}
              <ArrowRight
                aria-hidden="true"
                className="h-4 w-4 transition-transform motion-safe:group-hover:translate-x-1 rtl:rotate-180"
              />
            </span>
          ) : null}
        </div>

        {actions ? (
          <div className="relative z-10 mt-4">{actions}</div>
        ) : null}
      </div>
    </article>
  );
}

import { User } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import type { ResolvedPartProps } from "../types";

/**
 * Large variant — 2-column horizontal card. Image left, content right.
 * Used as the lead article in a magazine main column under a featured hero.
 */
